-- Reservations
SELECT id, productName, bookingDate, people, amountTotal, amountPaid, status, customerName, channel, createdAt, paidAt
FROM reservations WHERE customerName LIKE '%Rata%' OR customerEmail = 'jgrande@skicenter.es';

-- Invoices
SELECT id, invoiceNumber, clientName, total, status, issuedAt, quoteId, reservationId
FROM invoices WHERE clientName LIKE '%Rata%' OR clientEmail = 'jgrande@skicenter.es';

-- Transactions (accounting)
SELECT id, transactionNumber, type, amount, status, clientName, saleChannel, reservationId, invoiceNumber, createdAt
FROM transactions WHERE clientName LIKE '%Rata%' OR clientEmail = 'jgrande@skicenter.es';

-- Bookings (operational)
SELECT id, bookingNumber, clientName, scheduledDate, numberOfPersons, totalAmount, status, reservationId, sourceChannel
FROM bookings WHERE clientName LIKE '%Rata%' OR clientEmail = 'jgrande@skicenter.es';

